// src/lib/db/schema.ts — the canonical OotaOS schema. Copy verbatim.
// Every table here has a corresponding migration generated by drizzle-kit.
// Do NOT add tables without updating SKILL.md §4 first.

import {
  bigint,
  boolean,
  customType,
  index,
  integer,
  jsonb,
  pgEnum,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
  vector,
} from 'drizzle-orm/pg-core';

const bytea = customType<{ data: Buffer; driverData: Buffer }>({
  dataType() {
    return 'bytea';
  },
});

// ── Enums ────────────────────────────────────────────────────────────────
export const userRoleEnum = pgEnum('user_role', ['founder', 'team', 'advisor']);

export const firmTypeEnum = pgEnum('firm_type', [
  'vc',
  'cvc',
  'angel',
  'family_office',
  'accelerator',
  'syndicate',
]);

export const stageEnum = pgEnum('lead_stage', [
  'prospect',
  'contacted',
  'engaged',
  'nda_pending',
  'nda_signed',
  'meeting_scheduled',
  'diligence',
  'term_sheet',
  'funded',
  'closed_lost',
]);

export const interactionKindEnum = pgEnum('interaction_kind', [
  'page_view',
  'question_asked',
  'email_sent',
  'email_received',
  'document_viewed',
  'meeting_held',
  'note',
  'stage_change',
  'email_verified',
]);

export const documentKindEnum = pgEnum('document_kind', [
  'pitch_deck',
  'financial_model',
  'customer_refs',
  'tech_arch',
  'cap_table',
  'product_demo',
  'term_sheet',
  'other',
]);

export const watermarkPolicyEnum = pgEnum('watermark_policy', ['per_investor', 'static', 'none']);

export const aiAgentEnum = pgEnum('ai_agent', ['concierge', 'drafter', 'strategist', 'curator']);

export const aiOutcomeEnum = pgEnum('ai_outcome', ['ok', 'refused', 'error', 'injected']);

export const emailOutboxStatusEnum = pgEnum('email_outbox_status', [
  'draft',
  'approved',
  'queued',
  'sent',
  'bounced',
  'failed',
  'cancelled',
]);

// ── Workspaces ───────────────────────────────────────────────────────────
export const workspaces = pgTable('workspaces', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: text('name').notNull(),
  aiEnabled: boolean('ai_enabled').notNull().default(true),
  aiMonthlyCapUsd: integer('ai_monthly_cap_usd').notNull().default(50),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
});

// ── Users ────────────────────────────────────────────────────────────────
export const users = pgTable(
  'users',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    email: varchar('email', { length: 254 }).notNull(),
    passwordHash: text('password_hash').notNull(),
    totpSecret: text('totp_secret').notNull(),
    role: userRoleEnum('role').notNull(),
    displayName: text('display_name'),
    whatsappE164: text('whatsapp_e164'),
    publicEmail: text('public_email'),
    signatureMarkdown: text('signature_markdown'),
    companyName: text('company_name'),
    companyWebsite: text('company_website'),
    companyAddress: text('company_address'),
    logoUrl: text('logo_url'),
    avatarUrl: text('avatar_url'),
    defaultTimezone: text('default_timezone'),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    emailUnique: uniqueIndex('users_workspace_email_idx').on(t.workspaceId, t.email),
  }),
);

// ── Sessions (Lucia) ─────────────────────────────────────────────────────
export const sessions = pgTable('sessions', {
  id: text('id').primaryKey(),
  userId: uuid('user_id')
    .notNull()
    .references(() => users.id, { onDelete: 'cascade' }),
  expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
});

