// ── Deals ────────────────────────────────────────────────────────────────
export const deals = pgTable('deals', {
  id: uuid('id').primaryKey().defaultRandom(),
  workspaceId: uuid('workspace_id')
    .notNull()
    .references(() => workspaces.id, { onDelete: 'cascade' }),
  roundLabel: text('round_label').notNull(),
  targetSizeUsd: bigint('target_size_usd', { mode: 'number' }).notNull(),
  preMoneyUsd: bigint('pre_money_usd', { mode: 'number' }),
  postMoneyUsd: bigint('post_money_usd', { mode: 'number' }),
  committedUsd: bigint('committed_usd', { mode: 'number' }).notNull().default(0),
  seedFunded: boolean('seed_funded').notNull().default(false),
  companyType: text('company_type').notNull(),
  incorporationCountry: text('incorporation_country').notNull(),
  pitchJurisdiction: text('pitch_jurisdiction').notNull(),
  closeDate: timestamp('close_date', { withTimezone: true }),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
});

// ── Leads ────────────────────────────────────────────────────────────────
export const leads = pgTable(
  'leads',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    dealId: uuid('deal_id')
      .notNull()
      .references(() => deals.id, { onDelete: 'cascade' }),
    investorId: uuid('investor_id')
      .notNull()
      .references(() => investors.id, { onDelete: 'cascade' }),
    stage: stageEnum('stage').notNull().default('prospect'),
    stageEnteredAt: timestamp('stage_entered_at', { withTimezone: true }).notNull().defaultNow(),
    nextActionOwner: text('next_action_owner'),
    nextActionDue: timestamp('next_action_due', { withTimezone: true }),
    sourceOfLead: text('source_of_lead'),
    referrerName: text('referrer_name'),
    thesisFitScore: integer('thesis_fit_score'),
    internalNotes: text('internal_notes'),
    askUsd: bigint('ask_usd', { mode: 'number' }),
    offerTerms: jsonb('offer_terms'),
    // ── Relationship-state fields (moved from investors in the fundraising-OS refactor) ──
    warmthScore: integer('warmth_score'),
    introPath: text('intro_path'),
    lastContactAt: timestamp('last_contact_at', { withTimezone: true }),
    closedLostReason: text('closed_lost_reason'),
    fundedAmountUsd: bigint('funded_amount_usd', { mode: 'number' }),
    fundedAt: timestamp('funded_at', { withTimezone: true }),
    committedUsd: bigint('committed_usd', { mode: 'number' }),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    pipelineIdx: index('leads_pipeline_idx').on(t.workspaceId, t.stage, t.updatedAt),
  }),
);

// ── Interactions ─────────────────────────────────────────────────────────
export const interactions = pgTable(
  'interactions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    leadId: uuid('lead_id').references(() => leads.id, { onDelete: 'cascade' }),
    investorId: uuid('investor_id').references(() => investors.id, { onDelete: 'cascade' }),
    kind: interactionKindEnum('kind').notNull(),
    payload: jsonb('payload').notNull().default({}),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    timelineIdx: index('interactions_timeline_idx').on(t.leadId, t.createdAt),
    investorTimelineIdx: index('interactions_investor_timeline_idx').on(t.investorId, t.createdAt),
  }),
);

// ── Documents ────────────────────────────────────────────────────────────
export const documents = pgTable('documents', {
  id: uuid('id').primaryKey().defaultRandom(),
  workspaceId: uuid('workspace_id')
    .notNull()
    .references(() => workspaces.id, { onDelete: 'cascade' }),
  // Deal-scoping (rule #9). Nullable during transition; new uploads must set it.
  dealId: uuid('deal_id').references(() => deals.id),
  kind: documentKindEnum('kind').notNull(),
  title: text('title'),
  r2Key: text('r2_key').notNull(),
  originalFilename: text('original_filename').notNull(),
  mimeType: text('mime_type').notNull(),
  sizeBytes: integer('size_bytes').notNull(),
  sha256: text('sha256').notNull(),
  watermarkPolicy: watermarkPolicyEnum('watermark_policy').notNull().default('per_investor'),
  // Per-stage permissioning (rule #10). NULL = visible to any cookie-validated investor.
  minLeadStage: stageEnum('min_lead_stage'),
  expiresAt: timestamp('expires_at', { withTimezone: true }),
  uploadedBy: uuid('uploaded_by')
    .notNull()
    .references(() => users.id),
  deletedAt: timestamp('deleted_at', { withTimezone: true }),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
});

// ── Document Versions ────────────────────────────────────────────────────
// Every time a document is replaced, the previous row's bytes + metadata
// are archived here so the founder can audit what was shared with whom.
export const documentVersions = pgTable(
  'document_versions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    documentId: uuid('document_id')
      .notNull()
      .references(() => documents.id, { onDelete: 'cascade' }),
    version: integer('version').notNull(),
    kind: documentKindEnum('kind').notNull(),
    originalFilename: text('original_filename').notNull(),
    mimeType: text('mime_type').notNull(),
    sizeBytes: integer('size_bytes').notNull(),
    r2Key: text('r2_key').notNull(),
    sha256: text('sha256').notNull(),
    minLeadStage: stageEnum('min_lead_stage'),
    dealId: uuid('deal_id'),
    archivedAt: timestamp('archived_at', { withTimezone: true }).notNull().defaultNow(),
    archivedBy: uuid('archived_by').references(() => users.id),
  },
  (t) => ({
    lookupIdx: index('document_versions_workspace_doc_idx').on(
      t.workspaceId,
      t.documentId,
      t.version,
    ),
  }),
);

// ── Share Links ──────────────────────────────────────────────────────────
export const shareLinks = pgTable(
  'share_links',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    leadId: uuid('lead_id')
      .notNull()
      .references(() => leads.id, { onDelete: 'cascade' }),
    documentId: uuid('document_id')
      .notNull()
      .references(() => documents.id, { onDelete: 'cascade' }),
    token: text('token').notNull(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
    revokedAt: timestamp('revoked_at', { withTimezone: true }),
    downloadAllowed: boolean('download_allowed').notNull().default(false),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    tokenUnique: uniqueIndex('share_links_token_idx').on(t.token),
  }),
);

// ── NDAs ─────────────────────────────────────────────────────────────────
