// ── Google OAuth tokens ──────────────────────────────────────────────────
// Stores OAuth tokens per founder/user for Google Calendar event creation.
// One row per (workspace, user); refreshed on each use.
export const googleOauthTokens = pgTable(
  'google_oauth_tokens',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    accessToken: text('access_token').notNull(),
    refreshToken: text('refresh_token'),
    scope: text('scope').notNull(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
    calendarId: text('calendar_id').notNull().default('primary'),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    lookupIdx: index('google_oauth_tokens_lookup_idx').on(t.workspaceId, t.userId),
  }),
);

// ── Magic-link revocations ───────────────────────────────────────────────
// Stateless HMAC tokens can't carry a revoked bit, so we record a "revoked
// before <ts>" cutoff per investor. verifyInvestorLink consults this on
// every request and rejects tokens with issuedAt earlier than the cutoff.
export const investorLinkRevocations = pgTable(
  'investor_link_revocations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    investorId: uuid('investor_id')
      .notNull()
      .references(() => investors.id, { onDelete: 'cascade' }),
    revokedBefore: timestamp('revoked_before', { withTimezone: true }).notNull(),
    revokedAt: timestamp('revoked_at', { withTimezone: true }).notNull().defaultNow(),
    revokedBy: uuid('revoked_by').references(() => users.id),
    reason: text('reason'),
  },
  (t) => ({
    lookupIdx: index('investor_link_revocations_lookup_idx').on(t.workspaceId, t.investorId),
  }),
);

// ── Rate Limits ──────────────────────────────────────────────────────────
export const rateLimits = pgTable('rate_limits', {
  key: text('key').primaryKey(),
  tokens: integer('tokens').notNull(),
  refilledAt: timestamp('refilled_at', { withTimezone: true }).notNull().defaultNow(),
});

// ── Email Outbox ─────────────────────────────────────────────────────────
export const emailOutbox = pgTable(
  'email_outbox',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    toEmail: text('to_email').notNull(),
    subject: text('subject').notNull(),
    bodyText: text('body_text').notNull(),
    bodyHtml: text('body_html'),
    status: emailOutboxStatusEnum('status').notNull().default('draft'),
    attempts: integer('attempts').notNull().default(0),
    lastError: text('last_error'),
    sentAt: timestamp('sent_at', { withTimezone: true }),
    // Human-approval gate (rule #11). send route rejects unless status='approved'.
    approvedBy: uuid('approved_by').references(() => users.id),
    approvedAt: timestamp('approved_at', { withTimezone: true }),
    // Optional FK to a lead so we can enforce rule #3 (no outreach without a lead).
    leadId: uuid('lead_id').references(() => leads.id, { onDelete: 'set null' }),
    /** Drip cadence support — set to a future timestamp to defer dispatch. */
    scheduledFor: timestamp('scheduled_for', { withTimezone: true }),
    /** Groups multi-step cadences so a reply can cancel the rest. */
    cadenceGroupId: uuid('cadence_group_id'),
    /** 0-indexed position in the cadence; null for one-shot sends. */
    stepIndex: integer('step_index'),
    createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (t) => ({
    drainIdx: index('email_outbox_drain_idx').on(t.status, t.createdAt),
  }),
);

// ── Email Inbox ──────────────────────────────────────────────────────────
export const emailInbox = pgTable('email_inbox', {
  id: uuid('id').primaryKey().defaultRandom(),
  workspaceId: uuid('workspace_id')
    .notNull()
    .references(() => workspaces.id, { onDelete: 'cascade' }),
  imapUid: integer('imap_uid').notNull(),
  fromEmail: text('from_email').notNull(),
  subject: text('subject').notNull(),
  bodyText: text('body_text').notNull(),
  bodyHtml: text('body_html'),
  receivedAt: timestamp('received_at', { withTimezone: true }).notNull(),
  matchedLeadId: uuid('matched_lead_id').references(() => leads.id),
  processedAt: timestamp('processed_at', { withTimezone: true }),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
});

// ── Stored Files (Postgres file storage backend) ──────────────────────────
export const storedFiles = pgTable('stored_files', {
  storageKey: text('storage_key').primaryKey(),
  contentType: text('content_type').notNull(),
  sizeBytesOriginal: integer('size_bytes_original').notNull(),
  sizeBytesCompressed: integer('size_bytes_compressed').notNull(),
  content: bytea('content').notNull(),
  createdAt: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
});
